            { q: "De v = sqrt(γRT/M), despeja 'M'.", a: "M = γRT / v^2", d: "avanzado", type:"multiple_choice", options:["M = γRT / v", "M = (v^2)/(γRT)", "M = γRT / v^2"]},
            { q: "De y(x,t) = A sen(kx - ωt + φ), despeja 'ω'.", a: "ω = (kx - asin(y/A) + φ) / t", d: "avanzado", type:"multiple_choice", options:["ω = (kx+φ)/t", "ω = (kx - asin(y/A) + φ) / t", "ω = asin(y/A)"]}
