            { q: "La capacidad de evaluar la credibilidad de la fuente de un texto es crucial para hacer inferencias válidas.", a: "Verdadero", d: "avanzado", type: "multiple_choice", options: ["Verdadero", "Falso", "La fuente no importa, solo el texto"] }
